class UKNITBC( newcipher ):
    def __init__(self ):
        super().__init__( 'uKNIT-BC', (len( UKNIT_BC_MODEL ) + 1)//2  )

    def sbox( self, rx, sx ):
        assert rx < self.roundx, 'the number of rounds is wrong' 
        assert sx < 16, 'the number of sboxes is wrong'
        return UKNIT_BC_MODEL[ 2 * rx ][15 - sx]

    def matrix( self, rx ):
        C = UKNIT_BC_MODEL[ 2 * rx + 1 ]
        XORN = len( C ) # 3
        L = []
        for j in range( XORN ):
            L.append( C[j] )

        M = [ [ 0 for i in range(64) ] for j in range(64) ]
        for j in range( 64 ):
            for k in range( XORN ):
                if L[k][j] != -1:
                    #M[j][ 63 - L[k][j] ] = 1
                    M[63 - j][ 63 - L[k][j] ] = 1
        return M


def supp( x ):
    L = []
    for i in range(64):
        if x[i] > 0:
            L.append( i )
    return L

if __name__ == '__main__':
    uknit_bc = UKNITBC()

    for r in range(6, 7):
        for idx in range(16):
            print( idx )
            sbx = sbox( uknit_bc.sbox( r, idx ), 4, 4 )
            tb = sbx.genDLCT()
            sbx.print2DTable( tb, 4, 4 )
            #input()

    exit(0)

    F2 = galois.GF(2)

    MM = [ ]
    for i in range(11):
        MM.append( F2( uknit_bc.matrix(i) ) )

    for index in range(32, 64):
        L = [ index ]
        for m in range(11):
            M0 = MM[m]
            M0inv = np.linalg.inv( M0 ).tolist()
            L += supp( M0inv[index] ) 

        print( ' & '.join( list( map( str, L ) ) ), end = ' ' )
        print( r'\\' )




        

